var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"소대장! 놈들이 로스트 쉽 쪽으로 침입하고 있다!","JPN":"小隊長！　奴らがロストシップに侵入している！","ENG":"Cap! I see tangos approaching the Lost Ship!","TWN":"小隊長！那些傢伙往失落艦船的方向去了！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"지원은 멀었어?!","JPN":"支援はまだなのか！？","ENG":"Are we still waiting on backup?","TWN":"支援還沒到嗎！？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이 자식들, 박살내도 박살내도 계속 몰려와!","JPN":"こいつら、倒しても倒してもキリがねえ！","ENG":"They just keep coming and coming!","TWN":"這群混蛋，不管再怎麼打，還是不斷地湧上來！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"좋겠네, 아줌마. 시간을 끈 보람이 있어서.","JPN":"おばさん、よかったわね。時間稼ぎの甲斐があって。","ENG":"Well, good for you, lady. All that stalling is paying off for you.","TWN":"不錯喔，大嬸，時間拖延得很有價值喔。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사업상 의미 있는 결정이었다고 해 두죠.","JPN":"ビジネス上、意味がある決定だったとしましょう。","ENG":"Let’s just say it was the sound business decision to make.","TWN":"請把這稱作商業上的決策。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 결혼도 안 한 처녀에게 자꾸 아줌마라고 부르는 건 좀 적절하지 않은 것 같군요.","JPN":"あと、未婚の女性をおばさん呼ばわりするのは不適切だと思います。","ENG":"By the way, I don’t exactly appreciate your tone when you call me “lady,” as if I was some kind of an old married woman.","TWN":"另外，一直把一個沒過結婚的處女叫作大嬸，這樣有點不太合適吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"노처녀보단 낫잖아?","JPN":"オールドミスよりかはマシでしょ？","ENG":"Hey, it’s better than “old maid,” isn’t it?","TWN":"總比叫妳剩女好吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 내 기준에선 스무 살 이상이면 다 아줌마야.","JPN":"それにアタシの基準では、20歳越えればみんなおばさんよ。","ENG":"Besides, everyone older than 20 is an old lady in my books.","TWN":"而且按照我的標準，20歲以上都叫大嬸啦。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"기준이 꽤 타이트하군요.","JPN":"ずいぶん厳しい基準ですね。","ENG":"That’s a pretty strict standard you got there.","TWN":"妳的標準還真嚴格。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"실비아 양은 나이 안 먹을 것 같습니까?","JPN":"シルビアさんだっていずれ歳を取りますよ？","ENG":"You think you’ll stay young forever?","TWN":"希爾維亞小姐覺得自己的年齡不會增長嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"걱정 마. 연방정부 서버에 내가 스무 살 이상으로 기록될 일은 없거든.","JPN":"心配いらないわ。連邦政府のサーバーに、アタシが20歳以上で記録されることはないからね。","ENG":"Don't worry. I’ll never be over 20 on file, at least on the federal database.","TWN":"不用擔心，聯邦政府伺服器裡不會記錄我20歲以上的事情。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"두 분 다 괜찮으세요?","JPN":"お2人とも無事ですか？","ENG":"Are you two alright?","TWN":"兩位都沒事吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_RIFLE_FIRE"},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"물론. 이래 봬도 영화에나 나오는 미합중국 특수요원이라고.","JPN":"もちろん。こう見えても、映画に出てくるようなアメリカ合衆国の特殊部隊員だからね。","ENG":"Of course. I’m a super special federal agent, like the ones you see in the movies.","TWN":"當然，別看我這樣，我好歹也是電影裡會出現的美國特殊要員。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어중이떠중이들이랑은 겪은 아수라장의 숫자가 달라.","JPN":"その辺の有象無象とは、経験した修羅場の数が違うわ。","ENG":"I’ve seen more than my fair share of FUBAR situations. Way more than amateurs like y’all.","TWN":"和下層階級們比起來，我經歷過的修羅場實在多太多了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......아수라장에 대해서는 저도 할말이 많지만, 일단은 저도 괜찮습니다.","JPN":"……修羅場については私も言いたいことが山々ですが、一応私も大丈夫です。","ENG":"I could say the same about myself... but yeah, I’m fine too.","TWN":"……關於修羅場，我能說的也不少。不過先不提這些。我也沒事。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"알겠습니다.","JPN":"了解しました。","ENG":"Roger that.","TWN":"好的，我知道了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"적들이 너무 많아서 방어선을 유지하긴 힘들어요.","JPN":"敵が多すぎて、防衛線を維持するのが困難です。","ENG":"There’s too many of them for us to hold a line of defense.","TWN":"敵人太多了，很難維持防線。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"일단 두 분을 호위하면서 이곳에서 빠져나가는 걸 최우선 목표로 삼겠습니다.","JPN":"まずはお2人を護衛しながら、ここを脱出することを最優先目標にします。","ENG":"Our priority will be to escort you two out of here.","TWN":"我們會優先護送兩位離開這裡。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};